	"BUILD" NUMBER(*,5) DEFAULT 1 NOT NULL ENABLE
   ) ;
ALTER TABLE "DIRKSPZM32"."ISI_SCRIPT_CFG" ADD CONSTRAINT "CHECK_SCRIPT_ENABLED" CHECK (ENABLED in ('T','F')) ENABLE;
