ALTER TABLE "DIRKSPZM32"."ISI_SCRIPT_CFG" ADD CONSTRAINT "CHECK_SCRIPT_SOURCE_TYPE" CHECK (SCRIPT_SOURCE_TYPE in ('PascalScript')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_SCRIPT_CFG" ADD CONSTRAINT "PK_ISI_SCRIPT_CFG" PRIMARY KEY ("SID", "FIRMA_NR", "SCRIPT_ID")
  USING INDEX  ENABLE;


